{
  "meta": {
    "lastTouchedVersion": "{{OPENCLAW_VERSION}}",
    "lastTouchedAt": "{{SETUP_DATE}}"
  },
  "auth": {
    "profiles": {
      "anthropic:default": {
        "provider": "anthropic",
        "mode": "token"
      },
      "openai:default": {
        "provider": "openai",
        "mode": "api_key"
      }
    }
  },
  "models": {
    "providers": {
      "litellm": {
        "baseUrl": "{{LITELLM_BASE_URL}}",
        "apiKey": "{{LITELLM_API_KEY}}",
        "api": "openai-completions",
        "models": [
          {
            "id": "claude-opus-4-6",
            "name": "Claude Opus 4.6",
            "reasoning": true,
            "input": ["text", "image"],
            "contextWindow": 200000,
            "maxTokens": 8192
          },
          {
            "id": "claude-sonnet-4-6",
            "name": "Claude Sonnet 4.6",
            "reasoning": true,
            "input": ["text", "image"],
            "contextWindow": 200000,
            "maxTokens": 8192
          },
          {
            "id": "claude-haiku-4-5",
            "name": "Claude Haiku 4.5",
            "reasoning": false,
            "input": ["text"],
            "contextWindow": 200000,
            "maxTokens": 4096
          }
        ]
      }
    }
  },
  "agents": {
    "defaults": {
      "model": {
        "primary": "litellm/claude-opus-4-6",
        "fallbacks": [
          "litellm/claude-sonnet-4-6"
        ]
      },
      "workspace": "{{OPENCLAW_HOME}}/workspace",
      "compaction": {
        "mode": "safeguard"
      },
      "heartbeat": {
        "every": "60m",
        "model": "litellm/claude-sonnet-4-6",
        "target": "signal"
      },
      "maxConcurrent": 4,
      "subagents": {
        "maxConcurrent": 8
      }
    }
  },
  "tools": {
    "web": {
      "search": {
        "enabled": false
      },
      "fetch": {
        "enabled": false
      }
    }
  },
  "messages": {
    "ackReactionScope": "group-mentions"
  },
  "commands": {
    "native": "auto",
    "nativeSkills": "auto",
    "restart": true,
    "ownerDisplay": "raw"
  },
  "session": {
    "dmScope": "per-channel-peer"
  },
  "channels": {
    "signal": {
      "enabled": true,
      "account": "{{SIGNAL_PHONE_NUMBER}}",
      "cliPath": "signal-cli",
      "dmPolicy": "pairing",
      "groupPolicy": "allowlist"
    }
  },
  "gateway": {
    "port": 18789,
    "mode": "local",
    "bind": "loopback",
    "controlUi": {
      "allowedOrigins": ["{{CONTROL_UI_ORIGIN}}"]
    },
    "auth": {
      "mode": "token",
      "token": "{{GATEWAY_AUTH_TOKEN}}"
    },
    "tailscale": {
      "mode": "off",
      "resetOnExit": false
    },
    "nodes": {
      "denyCommands": [
        "camera.snap",
        "camera.clip",
        "screen.record",
        "contacts.add",
        "calendar.add",
        "reminders.add",
        "sms.send"
      ]
    }
  },
  "skills": {
    "install": {
      "nodeManager": "npm"
    }
  },
  "plugins": {
    "entries": {}
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://github.com/NickBorgersProbably/hide-my-list/.github/scripts/review/schema/fix-result-v1.json",
  "title": "Fix Result v1",
  "description": "Output of the agentic fixer stage in the v2 review pipeline. Consumed by the read-only judge (aggregate.mjs) to determine which reviewer blockers were actually addressed. Addressed entries MUST be namespaced as `<role>/<id>` so two reviewers emitting the same bare blocker id cannot cross-clear each other (see #342 design review).",
  "type": "object",
  "additionalProperties": false,
  "required": ["schema_version", "input_sha", "new_sha", "addressed", "skipped"],
  "properties": {
    "schema_version": { "const": "1" },
    "input_sha": {
      "type": "string",
      "pattern": "^[0-9a-f]{40}$",
      "description": "SHA the fixer started from. MUST equal the reviewers' reviewed_sha. The judge fails closed on mismatch."
    },
    "new_sha": {
      "type": "string",
      "pattern": "^[0-9a-f]{40}$",
      "description": "SHA after the fixer pushed (or input_sha if the fixer was a no-op)."
    },
    "addressed": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^(design|security|psych|docs|prompt)/.+$",
        "description": "Namespaced blocker id, e.g. \"security/sec-1\"."
      }
    },
    "skipped": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["id", "reason"],
        "properties": {
          "id": { "type": "string", "pattern": "^(design|security|psych|docs|prompt)/.+$" },
          "reason": { "type": "string", "minLength": 1 }
        }
      }
    },
    "tokens_used": { "type": "integer", "minimum": 0 },
    "duration_seconds": { "type": "integer", "minimum": 0 }
  }
}
